import React, { useEffect, useState } from "react";
import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
} from "chart.js";
import { Doughnut, Bar } from "react-chartjs-2";
import "./Dashboard.css";

ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title);

const Dashboard = () => {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const res = await fetch("/api/dashboard-stats");
        const data = await res.json();
        setStats(data);
      } catch (err) {
        console.error("Error loading stats:", err);
      }
    };
    fetchStats();
  }, []);

  if (!stats) return <div className="loading">Loading...</div>;

  const donutOptions = {
    cutout: "80%",
    plugins: {
      legend: { display: false },
      tooltip: { enabled: false },
    },
  };

  const renderDonut = (value, color) => ({
    data: {
      datasets: [
        {
          data: [value, 100 - value],
          backgroundColor: [color, "#e0e0e0"],
          borderWidth: 0,
        },
      ],
    },
  });

  const mainDonutData = {
    labels: ["Free", "Occupied", "Other"],
    datasets: [
      {
        data: [stats.pieChart.free, stats.pieChart.occupied, stats.resources.totalRooms - stats.pieChart.free - stats.pieChart.occupied],
        backgroundColor: ["#8bc34a", "#f44336", "#fdd835"],
        borderWidth: 0,
      },
    ],
  };

  const barData = {
    labels: Object.keys(stats.barChart),
    datasets: [
      {
        label: "Free Rooms",
        data: Object.values(stats.barChart),
        backgroundColor: "#c62828",
      },
    ],
  };

  return (
    <div className="dashboard-wrapper">
      <div className="dashboard-grid">
        <div className="card large">
          <h4>Availability</h4>
          <Doughnut data={mainDonutData} options={donutOptions} />
          <div className="donut-center-text">
            {stats.pieChart.free}
          </div>
        </div>

        <div className="card donut-small">
          <h4>Labs</h4>
          <Doughnut data={renderDonut(stats.resources.labs, "#fbc02d").data} options={donutOptions} />
          <div className="donut-center-text">{stats.resources.labs}</div>
        </div>

        <div className="card donut-small">
          <h4>Projectors</h4>
          <Doughnut data={renderDonut(stats.resources.projectorRooms, "#fdd835").data} options={donutOptions} />
          <div className="donut-center-text">{stats.resources.projectorRooms}</div>
        </div>

        <div className="card donut-small">
          <h4>Free</h4>
          <Doughnut data={renderDonut(stats.resources.totalRooms - stats.pieChart.occupied, "#e53935").data} options={donutOptions} />
          <div className="donut-center-text">
            {stats.resources.totalRooms - stats.pieChart.occupied}
          </div>
        </div>

        <div className="card donut-small">
          <h4>Occupied</h4>
          <Doughnut data={renderDonut(stats.pieChart.occupied, "#d32f2f").data} options={donutOptions} />
          <div className="donut-center-text">{stats.pieChart.occupied}</div>
        </div>

        <div className="card bar">
          <h3>Free Rooms Per Day</h3>
          <Bar
            data={barData}
            options={{
              responsive: true,
              plugins: { legend: { display: false } },
              scales: { y: { beginAtZero: true } },
            }}
          />
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
